const cp = require('child_process');
const scanDir = 'C:/Users/iohan/Documents';

try {
  // Get agent projects list
  const projects = cp.execSync('bash scripts/scan-projects.sh "' + scanDir + '" 2>&1', {cwd: 'C:/Users/iohan/Documents/ClaudeObsidian/agent-project-template', timeout: 30000, encoding: 'utf8'})
    .trim().split('\n').filter(l => l.includes('|true|')).map(l => ({name: l.split('|')[0], path: scanDir + '/' + l.split('|')[0]}));

  const alerts = [];
  for (const p of projects) {
    try {
      const output = cp.execSync('bash scripts/check-drift.sh 2>&1', {cwd: p.path, timeout: 30000, encoding: 'utf8'});
      const wMatch = output.match(/(\d+) warnings/);
      const eMatch = output.match(/(\d+) errors/);
      const w = wMatch ? parseInt(wMatch[1]) : 0;
      const e = eMatch ? parseInt(eMatch[1]) : 0;
      if (w > 0 || e > 0) alerts.push({project: p.name, warnings: w, errors: e});
    } catch(e) {
      alerts.push({project: p.name, warnings: 0, errors: 1, error: 'check-drift failed'});
    }
  }

  return [{json: {
    status: 'complete', total_alerts: alerts.length,
    message: alerts.length === 0 ? 'All projects healthy' : alerts.length + ' project(s) need attention',
    alerts, timestamp: new Date().toISOString()
  }}];
} catch(e) {
  return [{json: {status: 'error', error: (e.stderr || '') + e.message}}];
}
